#ifndef _BUCKETSORT_KERNEL_H_
#define _BUCKETSORT_KERNEL_H_

#include <stdio.h>

#define BUCKET_WARP_LOG_SIZE	5
#define BUCKET_WARP_N			1
#ifdef BUCKET_WG_SIZE_1
#define BUCKET_THREAD_N BUCKET_WG_SIZE_1
#else
#define BUCKET_THREAD_N			(BUCKET_WARP_N << BUCKET_WARP_LOG_SIZE)
#endif
#define BUCKET_BLOCK_MEMORY		(DIVISIONS * BUCKET_WARP_N)
#define BUCKET_BAND				128
#define LOG_DIVISIONS 10
#define DIVISIONS (1 << LOG_DIVISIONS)

__attribute__((always_inline))
int addOffset(local volatile unsigned int *s_offset, unsigned int data, unsigned int threadTag){
    unsigned int count;

    do{
        count = s_offset[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_offset[data] = count;
    }while(s_offset[data] != count);

	return (count & 0x07FFFFFFU) - 1;
}

kernel void
bucketcount( const global float *input, global int *indice, global unsigned int *d_prefixoffsets, int size, const global float *pivotPoints)
{
	local volatile unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

    const unsigned int threadTag = get_local_id(0) << (32 - BUCKET_WARP_LOG_SIZE);
    const int warpBase = (get_local_id(0) >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 
    const int numThreads = get_global_size(0);
	for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
		s_offset[i] = 0; 

	barrier(CLK_LOCAL_MEM_FENCE); 

	for (int tid = get_group_id(0) * get_local_size(0) + get_local_id(0); tid < size; tid += numThreads) {
		float elem = input[tid]; 

		int idx  = DIVISIONS/2 - 1; 
		int jump = DIVISIONS/4; 
		float piv = pivotPoints[idx]; 

		while(jump >= 1){
			idx = (elem < piv) ? (idx - jump) : (idx + jump);
			piv = pivotPoints[idx]; 
			jump /= 2; 
		}
		idx = (elem < piv) ? idx : (idx + 1); 

		indice[tid] = (addOffset(s_offset + warpBase, idx, threadTag) << LOG_DIVISIONS) + idx;  
	}

	barrier(CLK_LOCAL_MEM_FENCE); 

	int prefixBase = get_group_id(0) * BUCKET_BLOCK_MEMORY; 

	for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
		d_prefixoffsets[prefixBase + i] = s_offset[i] & 0x07FFFFFFU; 
}

kernel void bucketprefixoffset(global unsigned int *d_prefixoffsets, global unsigned int *d_offsets, int blocks) {
	int tid = get_group_id(0) * get_local_size(0) + get_local_id(0); 
	int size = blocks * BUCKET_BLOCK_MEMORY; 
	int sum = 0; 

	for (int i = tid; i < size; i += DIVISIONS) {
		int x = d_prefixoffsets[i]; 
		d_prefixoffsets[i] = sum; 
		sum += x; 
	}

	d_offsets[tid] = sum; 
}

kernel void
bucketsort(const global float *input, const global int *indice, global float *output, int size, const global unsigned int *d_prefixoffsets, 
		   const global unsigned int *l_offsets)
{
	local volatile unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

	int prefixBase = get_group_id(0) * BUCKET_BLOCK_MEMORY; 
    const int warpBase = (get_local_id(0) >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 
    const int numThreads = get_global_size(0);
	for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
		s_offset[i] = l_offsets[i & (DIVISIONS - 1)] + d_prefixoffsets[prefixBase + i]; 

	barrier(CLK_LOCAL_MEM_FENCE); 

	for (int tid = get_group_id(0) * get_local_size(0) + get_local_id(0); tid < size; tid += numThreads) {

		float elem = input[tid]; 
		int id = indice[tid]; 

		output[s_offset[warpBase + (id & (DIVISIONS - 1))] + (id >> LOG_DIVISIONS)] = elem;
	}
}

#endif

