#ifndef _MATRIXMUL_KERNEL_H_
#define _MATRIXMUL_KERNEL_H_

#include <stdio.h>

#define LOG_DIVISIONS 10
#define DIVISIONS (1 << LOG_DIVISIONS)

__attribute__((always_inline))
float4 sortElem(float4 r) {
	float4 nr;

	nr.x = (r.x > r.y) ? r.y : r.x; 
	nr.y = (r.y > r.x) ? r.y : r.x; 
	nr.z = (r.z > r.w) ? r.w : r.z; 
	nr.w = (r.w > r.z) ? r.w : r.z; 

	r.x = (nr.x > nr.z) ? nr.z : nr.x; 
	r.y = (nr.y > nr.w) ? nr.w : nr.y; 
	r.z = (nr.z > nr.x) ? nr.z : nr.x; 
	r.w = (nr.w > nr.y) ? nr.w : nr.y; 

	nr.x = r.x; 
	nr.y = (r.y > r.z) ? r.z : r.y; 
	nr.z = (r.z > r.y) ? r.z : r.y; 
	nr.w = r.w; 
	return nr; 
}

__attribute__((always_inline))
float4 getLowest(float4 a, float4 b)
{

	a.x = (a.x < b.w) ? a.x : b.w; 
	a.y = (a.y < b.z) ? a.y : b.z; 
	a.z = (a.z < b.y) ? a.z : b.y; 
	a.w = (a.w < b.x) ? a.w : b.x; 
	return a; 
}

__attribute__((always_inline))
float4 getHighest(float4 a, float4 b)
{
	b.x = (a.w >= b.x) ? a.w : b.x; 
	b.y = (a.z >= b.y) ? a.z : b.y; 
	b.z = (a.y >= b.z) ? a.y : b.z; 
	b.w = (a.x >= b.w) ? a.x : b.w; 
	return b; 
}

kernel void
mergeSortFirst(global float4 *result, int listsize, const global float *texData) 
{
    int bx = get_group_id(0);

	if(bx * get_local_size(0) + get_local_id(0) < listsize/4){
		float4 r;
		int idx = bx * get_local_size(0) + get_local_id(0);
		r.x = texData[idx * 4];
		r.y = texData[idx * 4 + 1];
		r.z = texData[idx * 4 + 2];
		r.w = texData[idx * 4 + 3];
		result[bx * get_local_size(0) + get_local_id(0)] = sortElem(r); 
	}
}

kernel void
mergeSortPass(global float4 *result, int nrElems, int threadsPerDiv, const global int *constStartAddr, const global float *texData) 
{
	int tid = (get_group_id(0) * get_local_size(0)) + get_local_id(0); 

	int division = tid / threadsPerDiv; 
	if(division >= DIVISIONS) return; 

	int int_tid = tid - division * threadsPerDiv; 
	int Astart = constStartAddr[division] + int_tid * nrElems; 

	int Bstart = Astart + nrElems/2;
	float4 *resStart = &(result[Astart]); 

	if(Astart >= constStartAddr[division + 1]) 
		return; 
	if(Bstart >= constStartAddr[division + 1]){
		for(int i=0; i<(constStartAddr[division + 1] - Astart); i++)
		{
			int idx = Astart + i;
			float4 elem;
			elem.x = texData[idx * 4];
			elem.y = texData[idx * 4 + 1];
			elem.z = texData[idx * 4 + 2];
			elem.w = texData[idx * 4 + 3];
			resStart[i] = elem;
		}
		return; 
	}

	int aidx = 0; 
	int bidx = 0; 
	int outidx = 0; 
	float4 a, b;

	int idx_a = Astart + aidx;
	a.x = texData[idx_a * 4];
	a.y = texData[idx_a * 4 + 1];
	a.z = texData[idx_a * 4 + 2];
	a.w = texData[idx_a * 4 + 3];

	int idx_b = Bstart + bidx;
	b.x = texData[idx_b * 4];
	b.y = texData[idx_b * 4 + 1];
	b.z = texData[idx_b * 4 + 2];
	b.w = texData[idx_b * 4 + 3];

	while(true)
	{
		float4 nextA, nextB;

		int idx_next_a = Astart + aidx + 1;
		nextA.x = texData[idx_next_a * 4];
		nextA.y = texData[idx_next_a * 4 + 1];
		nextA.z = texData[idx_next_a * 4 + 2];
		nextA.w = texData[idx_next_a * 4 + 3];

		int idx_next_b = Bstart + bidx + 1;
		nextB.x = texData[idx_next_b * 4];
		nextB.y = texData[idx_next_b * 4 + 1];
		nextB.z = texData[idx_next_b * 4 + 2];
		nextB.w = texData[idx_next_b * 4 + 3];

		float4 na = getLowest(a,b); 
		float4 nb = getHighest(a,b); 
		a = sortElem(na); 
		b = sortElem(nb); 

		resStart[outidx++] = a; 

		bool elemsLeftInA; 
		bool elemsLeftInB;

		elemsLeftInA = (aidx + 1 < nrElems/2); 
		elemsLeftInB = (bidx + 1 < nrElems/2) && (Bstart + bidx + 1 < constStartAddr[division + 1]); 

		if(elemsLeftInA){
			if(elemsLeftInB){
				if(nextA.x < nextB.x) { aidx += 1; a = nextA; }  
				else { bidx += 1;  a = nextB; }
			}
			else {
				aidx += 1; a = nextA;
			}
		}
		else {
			if(elemsLeftInB){
				bidx += 1;  a = nextB;
			}
			else {
				break; 
			}
		}

	}
	resStart[outidx++] = b;
}

kernel void
mergepack(global float *orig, global float *result, const global int *finalStartAddr, const global int *constStartAddr, const global int *nullElems) 
{
	int idx = (get_group_id(0) * get_local_size(0)) + get_local_id(0); 
	int division = get_group_id(1); 

	if((finalStartAddr[division] + idx) >= finalStartAddr[division + 1]) return; 
	result[finalStartAddr[division] + idx] = orig[constStartAddr[division]*4 + nullElems[division] + idx]; 
}

#endif
